#!/usr/bin/env node
/**
 * 将 specs/platform-publish-standards.csv 同步为：
 * - references/platform-publish-standards.md（审核参考手册）
 * - rules/{platform}.yaml（数值类硬规则，AUTO-GENERATED）
 *
 * 维护方式：只改 CSV，然后 npm run review:sync-specs
 */
import { readFileSync, writeFileSync, statSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';
import {
  buildAllPlatformYamls,
  CSV_PLATFORM_IDS,
  MANUAL_RULE_PLATFORMS,
} from './lib/sync-rules-builder.mjs';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const CSV_PATH = join(ROOT, 'specs', 'platform-publish-standards.csv');
const OUT_MD = join(ROOT, 'references', 'platform-publish-standards.md');
const RULES_DIR = join(ROOT, 'rules');

const COLUMNS = [
  { key: 'carrier', header: '内容载体' },
  { key: 'aspect', header: '画面比例 & 分辨率' },
  { key: 'duration', header: '时长 / 图片数量限制' },
  { key: 'size', header: '文件大小上限' },
  { key: 'cover', header: '封面要求' },
  { key: 'copy', header: '文案 / 标题字数' },
  { key: 'hashtag', header: '标签 Hashtag 规则' },
  { key: 'subtitle', header: '字幕规范' },
  { key: 'compliance', header: '平台专属制作要点 & 合规' },
];

/**
 * @param {string} line
 * @returns {string[]}
 */
function parseCsvLine(line) {
  const fields = [];
  let current = '';
  for (let i = 0; i < line.length; i += 1) {
    const ch = line[i];
    if (ch === ',') {
      fields.push(current);
      current = '';
    } else {
      current += ch;
    }
  }
  fields.push(current);
  return fields;
}

/**
 * @param {string} text
 */
export function parseCsv(text) {
  const lines = text.replace(/\r\n/g, '\n').replace(/^\uFEFF/, '').split('\n').filter((l) => l.trim());
  if (lines.length < 2) {
    throw new Error('CSV 至少需要表头与一行数据');
  }

  const rows = [];
  let currentPlatform = '';

  for (let i = 1; i < lines.length; i += 1) {
    const fields = parseCsvLine(lines[i]);
    if (fields.length < 10) {
      throw new Error(`第 ${i + 1} 行列数不足（期望 10 列，实际 ${fields.length}）`);
    }

    const platformCell = fields[0].trim();
    if (platformCell) {
      currentPlatform = platformCell;
    }
    if (!currentPlatform) {
      throw new Error(`第 ${i + 1} 行缺少平台名称`);
    }

    rows.push({
      platform: currentPlatform,
      carrier: fields[1].trim(),
      aspect: fields[2].trim(),
      duration: fields[3].trim(),
      size: fields[4].trim(),
      cover: fields[5].trim(),
      copy: fields[6].trim(),
      hashtag: fields[7].trim(),
      subtitle: fields[8].trim(),
      compliance: fields[9].trim(),
    });
  }

  return rows;
}

/**
 * @param {string} s
 */
function slugify(s) {
  return s
    .toLowerCase()
    .replace(/[（(].*?[）)]/g, '')
    .replace(/[^a-z0-9\u4e00-\u9fff]+/gi, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48) || 'platform';
}

/**
 * @param {string} compliance
 */
function formatCompliance(compliance) {
  if (!compliance) return '—';
  const parts = compliance
    .split(/(?=\d+\.\s)/)
    .map((p) => p.trim())
    .filter(Boolean);
  if (parts.length <= 1) {
    return compliance;
  }
  return parts.map((p) => `- ${p}`).join('\n');
}

/**
 * @param {ReturnType<typeof parseCsv>} rows
 */
function buildMarkdown(rows) {
  const generatedAt = new Date().toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' });
  const csvStat = statSync(CSV_PATH);
  const csvMtime = csvStat.mtime.toLocaleString('zh-CN', { timeZone: 'Asia/Shanghai' });

  const lines = [
    '<!-- AUTO-GENERATED by npm run review:sync-specs — 勿手改；请编辑 specs/platform-publish-standards.csv -->',
    '',
    '# 各平台发布内容参考标准',
    '',
    '> **审核员参考手册**：对照本文件做软审核；**数值上限**同步至 `rules/*.yaml` 供 `review:lint` 硬检。',
    '>',
    `> 源文件：[\`specs/platform-publish-standards.csv\`](../specs/platform-publish-standards.csv)`,
    `> 生成时间：${generatedAt}（北京时间） · CSV 修改时间：${csvMtime}`,
    '',
    '## 使用说明',
    '',
    '1. **维护**：只编辑 `specs/platform-publish-standards.csv`，保存后执行 `npm run review:sync-specs`',
    '2. **审核**：`content-reviewer` 按**平台 + 内容载体**找到对应小节做软审核',
    '3. **硬规则**：CSV 中可解析的数值上限（标题/正文字数、标签数等）自动写入 `rules/{platform}.yaml`',
    '4. **默认载体**：用户未说明时，选用标注「主推」的载体行',
    '',
    '## 平台索引',
    '',
  ];

  const platformGroups = new Map();
  for (const row of rows) {
    if (!platformGroups.has(row.platform)) {
      platformGroups.set(row.platform, []);
    }
    platformGroups.get(row.platform).push(row);
  }

  for (const [platform] of platformGroups) {
    lines.push(`- [${platform}](#${slugify(platform)})`);
  }

  lines.push('');

  for (const [platform, platformRows] of platformGroups) {
    const anchor = slugify(platform);
    lines.push(`## ${platform}`, '');
    lines.push(`<a id="${anchor}"></a>`, '');

    for (const row of platformRows) {
      const isPrimary = row.carrier.includes('主推');
      lines.push(`### ${row.carrier}${isPrimary ? ' ★' : ''}`, '');
      lines.push('| 项目 | 标准 |');
      lines.push('|------|------|');
      for (const col of COLUMNS) {
        const val = row[col.key];
        const display =
          col.key === 'compliance' ? formatCompliance(val).replace(/\n/g, '<br>') : val || '—';
        lines.push(`| ${col.header} | ${display} |`);
      }
      lines.push('');
    }
  }

  lines.push('---', '', '*由 `skills/content-reviewer/scripts/sync-publish-specs.mjs` 自动生成*', '');
  return lines.join('\n');
}

function main() {
  const csv = readFileSync(CSV_PATH, 'utf8');
  const rows = parseCsv(csv);

  writeFileSync(OUT_MD, buildMarkdown(rows), 'utf8');
  console.log(`✅ Markdown: ${rows.length} 行 → ${OUT_MD}`);

  const yamls = buildAllPlatformYamls(rows);
  for (const [platformId, content] of yamls) {
    const outPath = join(RULES_DIR, `${platformId}.yaml`);
    writeFileSync(outPath, content, 'utf8');
    console.log(`✅ rules/${platformId}.yaml`);
  }

  const manual = [...MANUAL_RULE_PLATFORMS].filter((p) => p !== '_common');
  console.log(`ℹ️  未覆盖（手写维护）: ${manual.join(', ')}`);
  console.log(`ℹ️  CSV 平台映射: ${Object.keys(CSV_PLATFORM_IDS).length} 个`);
}

main();
